/**
 * Scraper Rate Limiter Tests
 */

import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
import { ScraperRateLimiter, ScraperRateLimitConfig } from './scraperRateLimiter';
import { ErrorCode } from '../constants/errorCodes';

describe('ScraperRateLimiter', () => {
  let rateLimiter: ScraperRateLimiter;

  beforeEach(() => {
    rateLimiter = new ScraperRateLimiter();
  });

  afterEach(() => {
    rateLimiter.destroy();
  });

  describe('checkRateLimit', () => {
    it('should allow first request', async () => {
      const config: ScraperRateLimitConfig = {
        requestsPerMinute: 10,
      };

      await expect(
        rateLimiter.checkRateLimit('source-1', config)
      ).resolves.not.toThrow();
    });

    it('should allow requests within limit', async () => {
      const config: ScraperRateLimitConfig = {
        requestsPerMinute: 5,
      };

      // Make 5 requests
      for (let i = 0; i < 5; i++) {
        await expect(
          rateLimiter.checkRateLimit('source-1', config)
        ).resolves.not.toThrow();
      }
    });

    it('should throw error when rate limit exceeded', async () => {
      const config: ScraperRateLimitConfig = {
        requestsPerMinute: 3,
      };

      // Make 3 requests (at limit)
      for (let i = 0; i < 3; i++) {
        await rateLimiter.checkRateLimit('source-1', config);
      }

      // 4th request should fail
      await expect(
        rateLimiter.checkRateLimit('source-1', config)
      ).rejects.toThrow();
    });

    it('should enforce minimum delay between requests', async () => {
      const config: ScraperRateLimitConfig = {
        requestsPerMinute: 10,
        minDelay: 100, // 100ms minimum delay
      };

      const start = Date.now();
      await rateLimiter.checkRateLimit('source-1', config);
      await rateLimiter.checkRateLimit('source-1', config);
      const elapsed = Date.now() - start;

      // Should have waited at least 100ms
      expect(elapsed).toBeGreaterThanOrEqual(100);
    });

    it('should enforce burst limit', async () => {
      const config: ScraperRateLimitConfig = {
        requestsPerMinute: 10,
        burstLimit: 3,
      };

      // Make 3 requests (burst limit)
      for (let i = 0; i < 3; i++) {
        await rateLimiter.checkRateLimit('source-1', config);
      }

      // 4th request should fail even though we're under requestsPerMinute
      await expect(
        rateLimiter.checkRateLimit('source-1', config)
      ).rejects.toThrow();
    });

    it('should track rate limits per source independently', async () => {
      const config: ScraperRateLimitConfig = {
        requestsPerMinute: 2,
      };

      // Source 1: make 2 requests
      await rateLimiter.checkRateLimit('source-1', config);
      await rateLimiter.checkRateLimit('source-1', config);

      // Source 1: 3rd request should fail
      await expect(
        rateLimiter.checkRateLimit('source-1', config)
      ).rejects.toThrow();

      // Source 2: should still be able to make requests
      await expect(
        rateLimiter.checkRateLimit('source-2', config)
      ).resolves.not.toThrow();
    });
  });

  describe('executeWithRateLimit', () => {
    it('should execute operation when rate limit allows', async () => {
      const config: ScraperRateLimitConfig = {
        requestsPerMinute: 10,
      };

      const operation = vi.fn().mockResolvedValue('success');

      const result = await rateLimiter.executeWithRateLimit(
        'source-1',
        config,
        operation
      );

      expect(result).toBe('success');
      expect(operation).toHaveBeenCalledTimes(1);
    });

    it('should throw error when rate limit exceeded', async () => {
      const config: ScraperRateLimitConfig = {
        requestsPerMinute: 1,
      };

      const operation = vi.fn().mockResolvedValue('success');

      // First request succeeds
      await rateLimiter.executeWithRateLimit('source-1', config, operation);

      // Second request should fail
      await expect(
        rateLimiter.executeWithRateLimit('source-1', config, operation)
      ).rejects.toThrow();

      expect(operation).toHaveBeenCalledTimes(1);
    });

    it('should propagate operation errors', async () => {
      const config: ScraperRateLimitConfig = {
        requestsPerMinute: 10,
      };

      const operation = vi.fn().mockRejectedValue(new Error('Operation failed'));

      await expect(
        rateLimiter.executeWithRateLimit('source-1', config, operation)
      ).rejects.toThrow('Operation failed');
    });
  });

  describe('getRateLimitStatus', () => {
    it('should return correct status for new source', () => {
      const config: ScraperRateLimitConfig = {
        requestsPerMinute: 10,
      };

      const status = rateLimiter.getRateLimitStatus('source-1', config);

      expect(status.requestsInLastMinute).toBe(0);
      expect(status.limit).toBe(10);
      expect(status.remaining).toBe(10);
      expect(status.isLimited).toBe(false);
    });

    it('should return correct status after requests', async () => {
      const config: ScraperRateLimitConfig = {
        requestsPerMinute: 10,
      };

      // Make 3 requests
      for (let i = 0; i < 3; i++) {
        await rateLimiter.checkRateLimit('source-1', config);
      }

      const status = rateLimiter.getRateLimitStatus('source-1', config);

      expect(status.requestsInLastMinute).toBe(3);
      expect(status.limit).toBe(10);
      expect(status.remaining).toBe(7);
      expect(status.isLimited).toBe(false);
    });

    it('should show limited status when at limit', async () => {
      const config: ScraperRateLimitConfig = {
        requestsPerMinute: 3,
      };

      // Make 3 requests
      for (let i = 0; i < 3; i++) {
        await rateLimiter.checkRateLimit('source-1', config);
      }

      const status = rateLimiter.getRateLimitStatus('source-1', config);

      expect(status.requestsInLastMinute).toBe(3);
      expect(status.remaining).toBe(0);
      expect(status.isLimited).toBe(true);
    });
  });

  describe('resetRateLimit', () => {
    it('should reset rate limit for source', async () => {
      const config: ScraperRateLimitConfig = {
        requestsPerMinute: 2,
      };

      // Make 2 requests
      await rateLimiter.checkRateLimit('source-1', config);
      await rateLimiter.checkRateLimit('source-1', config);

      // Should be at limit
      await expect(
        rateLimiter.checkRateLimit('source-1', config)
      ).rejects.toThrow();

      // Reset
      rateLimiter.resetRateLimit('source-1');

      // Should be able to make requests again
      await expect(
        rateLimiter.checkRateLimit('source-1', config)
      ).resolves.not.toThrow();
    });
  });

  describe('calculateOptimalDelay', () => {
    it('should return 0 for new source', () => {
      const config: ScraperRateLimitConfig = {
        requestsPerMinute: 10,
      };

      const delay = rateLimiter.calculateOptimalDelay('source-1', config);

      expect(delay).toBe(0);
    });

    it('should return delay when at limit', async () => {
      const config: ScraperRateLimitConfig = {
        requestsPerMinute: 2,
      };

      // Make 2 requests
      await rateLimiter.checkRateLimit('source-1', config);
      await rateLimiter.checkRateLimit('source-1', config);

      const delay = rateLimiter.calculateOptimalDelay('source-1', config);

      // Should have some delay (close to 60000ms)
      expect(delay).toBeGreaterThan(0);
      expect(delay).toBeLessThanOrEqual(60000);
    });

    it('should return minDelay when specified', async () => {
      const config: ScraperRateLimitConfig = {
        requestsPerMinute: 10,
        minDelay: 500,
      };

      // Make 1 request
      await rateLimiter.checkRateLimit('source-1', config);

      // Immediately check delay
      const delay = rateLimiter.calculateOptimalDelay('source-1', config);

      // Should be close to minDelay
      expect(delay).toBeGreaterThan(0);
      expect(delay).toBeLessThanOrEqual(500);
    });
  });

  describe('getAllRateLimitStatuses', () => {
    it('should return empty object for no sources', () => {
      const statuses = rateLimiter.getAllRateLimitStatuses();

      expect(statuses).toEqual({});
    });

    it('should return statuses for all sources', async () => {
      const config: ScraperRateLimitConfig = {
        requestsPerMinute: 10,
      };

      // Make requests for multiple sources
      await rateLimiter.checkRateLimit('source-1', config);
      await rateLimiter.checkRateLimit('source-2', config);
      await rateLimiter.checkRateLimit('source-1', config);

      const statuses = rateLimiter.getAllRateLimitStatuses();

      expect(Object.keys(statuses)).toHaveLength(2);
      expect(statuses['source-1'].requestsInLastMinute).toBe(2);
      expect(statuses['source-2'].requestsInLastMinute).toBe(1);
    });
  });

  describe('waitForRateLimit', () => {
    it('should not wait when no delay needed', async () => {
      const config: ScraperRateLimitConfig = {
        requestsPerMinute: 10,
      };

      const start = Date.now();
      await rateLimiter.waitForRateLimit('source-1', config);
      const elapsed = Date.now() - start;

      // Should be very quick (< 10ms)
      expect(elapsed).toBeLessThan(10);
    });

    it('should wait when minDelay specified', async () => {
      const config: ScraperRateLimitConfig = {
        requestsPerMinute: 10,
        minDelay: 100,
      };

      // Make first request
      await rateLimiter.checkRateLimit('source-1', config);

      // Wait for rate limit
      const start = Date.now();
      await rateLimiter.waitForRateLimit('source-1', config);
      const elapsed = Date.now() - start;

      // Should have waited at least 100ms
      expect(elapsed).toBeGreaterThanOrEqual(90); // Allow small margin
    });
  });

  describe('error handling', () => {
    it('should throw error with correct error code', async () => {
      const config: ScraperRateLimitConfig = {
        requestsPerMinute: 1,
      };

      // Make first request
      await rateLimiter.checkRateLimit('source-1', config);

      // Second request should throw with correct error code
      try {
        await rateLimiter.checkRateLimit('source-1', config);
        expect.fail('Should have thrown error');
      } catch (error: any) {
        expect(error.errorCode).toBe(ErrorCode.SCRAPER_RATE_LIMITED);
        expect(error.statusCode).toBe(429);
        expect(error.details).toHaveProperty('retryAfter');
      }
    });

    it('should include retry information in error', async () => {
      const config: ScraperRateLimitConfig = {
        requestsPerMinute: 1,
      };

      // Make first request
      await rateLimiter.checkRateLimit('source-1', config);

      // Second request should throw with retry info
      try {
        await rateLimiter.checkRateLimit('source-1', config);
        expect.fail('Should have thrown error');
      } catch (error: any) {
        expect(error.details.retryAfter).toBeGreaterThan(0);
        expect(error.details.sourceId).toBe('source-1');
        expect(error.details.requestsPerMinute).toBe(1);
      }
    });
  });

  describe('integration with error recovery', () => {
    it('should retry on rate limit errors', async () => {
      const config: ScraperRateLimitConfig = {
        requestsPerMinute: 1,
        minDelay: 10, // Short delay for testing
      };

      let attemptCount = 0;
      const operation = vi.fn(async () => {
        attemptCount++;
        if (attemptCount === 1) {
          // First attempt: make a request to hit rate limit
          await rateLimiter.checkRateLimit('source-1', config);
          return 'success';
        } else {
          // Subsequent attempts: should wait and succeed
          return 'success';
        }
      });

      // This should succeed after retry
      const result = await rateLimiter.executeWithRateLimitAndRecovery(
        'source-1',
        config,
        operation,
        { maxRetries: 2 }
      );

      expect(result).toBe('success');
    });
  });

  describe('cleanup', () => {
    it('should clean up old entries', async () => {
      const config: ScraperRateLimitConfig = {
        requestsPerMinute: 10,
      };

      // Make requests
      await rateLimiter.checkRateLimit('source-1', config);
      await rateLimiter.checkRateLimit('source-2', config);

      // Verify entries exist
      let statuses = rateLimiter.getAllRateLimitStatuses();
      expect(Object.keys(statuses)).toHaveLength(2);

      // Manually trigger cleanup (would normally happen via interval)
      // For testing, we'll just verify the destroy method works
      rateLimiter.destroy();

      // Create new instance
      rateLimiter = new ScraperRateLimiter();

      // Should be empty
      statuses = rateLimiter.getAllRateLimitStatuses();
      expect(Object.keys(statuses)).toHaveLength(0);
    });
  });

  describe('concurrent requests', () => {
    it('should handle concurrent requests correctly', async () => {
      const config: ScraperRateLimitConfig = {
        requestsPerMinute: 5,
      };

      // Make 5 concurrent requests
      const promises = Array.from({ length: 5 }, () =>
        rateLimiter.checkRateLimit('source-1', config)
      );

      // All should succeed
      await expect(Promise.all(promises)).resolves.not.toThrow();

      // 6th request should fail
      await expect(
        rateLimiter.checkRateLimit('source-1', config)
      ).rejects.toThrow();
    });
  });
});

/**
 * Scraper Rate Limiting Integration Tests
 * Tests integration between rate limiter, queue service, and scraper service
 */

import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
import { ScraperQueueService } from '../services/scraperQueueService';
import { scraperRateLimiter, ScraperRateLimitConfig } from '../services/scraperRateLimiter';

describe('Scraper Rate Limiting Integration', () => {
  let queueService: ScraperQueueService;

  beforeEach(() => {
    queueService = new ScraperQueueService();
  });

  afterEach(() => {
    queueService.clearAll();
    scraperRateLimiter.destroy();
  });

  describe('Queue Service with Rate Limiting', () => {
    it('should execute job with rate limiting', async () => {
      const job = queueService.enqueueJob('source-1');

      const rateLimitConfig: ScraperRateLimitConfig = {
        requestsPerMinute: 10,
        minDelay: 100,
      };

      const operation = vi.fn().mockResolvedValue({ success: true });

      const result = await queueService.executeJobWithRecovery(
        job.id,
        operation,
        rateLimitConfig
      );

      expect(result).toEqual({ success: true });
      expect(operation).toHaveBeenCalledTimes(1);

      const completedJob = queueService.getJobStatus(job.id);
      expect(completedJob?.status).toBe('SUCCESS');
    });

    it('should handle rate limit errors in job execution', async () => {
      const rateLimitConfig: ScraperRateLimitConfig = {
        requestsPerMinute: 1,
      };

      // First job should succeed
      const job1 = queueService.enqueueJob('source-1');
      const operation1 = vi.fn().mockResolvedValue({ success: true });

      await queueService.executeJobWithRecovery(
        job1.id,
        operation1,
        rateLimitConfig
      );

      expect(queueService.getJobStatus(job1.id)?.status).toBe('SUCCESS');

      // Second job should fail due to rate limit (but will retry)
      const job2 = queueService.enqueueJob('source-1');
      const operation2 = vi.fn().mockResolvedValue({ success: true });

      // This will throw because rate limit is exceeded and retries will also fail quickly
      await expect(
        queueService.executeJobWithRecovery(
          job2.id,
          operation2,
          rateLimitConfig
        )
      ).rejects.toThrow();

      const failedJob = queueService.getJobStatus(job2.id);
      expect(failedJob?.status).toBe('FAILED');
      expect(failedJob?.error).toContain('Rate limit exceeded');
    });

    it('should retry job on rate limit error', async () => {
      const rateLimitConfig: ScraperRateLimitConfig = {
        requestsPerMinute: 2,
        minDelay: 50,
      };

      let callCount = 0;
      const operation = vi.fn(async () => {
        callCount++;
        // First call succeeds, establishing rate limit
        if (callCount === 1) {
          return { success: true };
        }
        // Subsequent calls should also succeed after waiting
        return { success: true };
      });

      // First job
      const job1 = queueService.enqueueJob('source-1');
      await queueService.executeJobWithRecovery(
        job1.id,
        operation,
        rateLimitConfig
      );

      // Second job (should wait due to minDelay)
      const job2 = queueService.enqueueJob('source-1');
      const start = Date.now();
      await queueService.executeJobWithRecovery(
        job2.id,
        operation,
        rateLimitConfig
      );
      const elapsed = Date.now() - start;

      // Should have waited at least minDelay
      expect(elapsed).toBeGreaterThanOrEqual(50);
      expect(queueService.getJobStatus(job2.id)?.status).toBe('SUCCESS');
    });

    it('should get rate limit status for source', () => {
      const rateLimitConfig: ScraperRateLimitConfig = {
        requestsPerMinute: 10,
      };

      const status = queueService.getRateLimitStatus('source-1', rateLimitConfig);

      expect(status.limit).toBe(10);
      expect(status.remaining).toBe(10);
      expect(status.isLimited).toBe(false);
    });

    it('should reset rate limit for source', async () => {
      const rateLimitConfig: ScraperRateLimitConfig = {
        requestsPerMinute: 1,
      };

      // Make a request to establish rate limit
      await scraperRateLimiter.checkRateLimit('source-1', rateLimitConfig);

      // Should be at limit
      let status = queueService.getRateLimitStatus('source-1', rateLimitConfig);
      expect(status.remaining).toBe(0);

      // Reset
      queueService.resetRateLimit('source-1');

      // Should be cleared
      status = queueService.getRateLimitStatus('source-1', rateLimitConfig);
      expect(status.remaining).toBe(1);
    });

    it('should get all rate limit statuses', async () => {
      const rateLimitConfig: ScraperRateLimitConfig = {
        requestsPerMinute: 10,
      };

      // Make requests for multiple sources
      await scraperRateLimiter.checkRateLimit('source-1', rateLimitConfig);
      await scraperRateLimiter.checkRateLimit('source-2', rateLimitConfig);

      const statuses = queueService.getAllRateLimitStatuses();

      expect(Object.keys(statuses)).toHaveLength(2);
      expect(statuses['source-1']).toBeDefined();
      expect(statuses['source-2']).toBeDefined();
    });
  });

  describe('Multiple Sources Rate Limiting', () => {
    it('should enforce rate limits independently per source', async () => {
      const rateLimitConfig: ScraperRateLimitConfig = {
        requestsPerMinute: 1,
      };

      const operation = vi.fn().mockResolvedValue({ success: true });

      // Source 1: first job
      const job1 = queueService.enqueueJob('source-1');
      await queueService.executeJobWithRecovery(
        job1.id,
        operation,
        rateLimitConfig
      );

      // Source 2: should succeed even though source-1 is at limit
      const job2 = queueService.enqueueJob('source-2');
      await queueService.executeJobWithRecovery(
        job2.id,
        operation,
        rateLimitConfig
      );

      expect(queueService.getJobStatus(job1.id)?.status).toBe('SUCCESS');
      expect(queueService.getJobStatus(job2.id)?.status).toBe('SUCCESS');

      // Source 1: second job should fail
      const job3 = queueService.enqueueJob('source-1');
      await expect(
        queueService.executeJobWithRecovery(
          job3.id,
          operation,
          rateLimitConfig
        )
      ).rejects.toThrow();
    });

    it('should handle different rate limits per source', async () => {
      const fastConfig: ScraperRateLimitConfig = {
        requestsPerMinute: 10,
      };

      const slowConfig: ScraperRateLimitConfig = {
        requestsPerMinute: 2,
      };

      const operation = vi.fn().mockResolvedValue({ success: true });

      // Fast source: make 5 requests (should all succeed)
      for (let i = 0; i < 5; i++) {
        const job = queueService.enqueueJob('fast-source');
        await queueService.executeJobWithRecovery(
          job.id,
          operation,
          fastConfig
        );
      }

      // Slow source: make 2 requests (should succeed)
      for (let i = 0; i < 2; i++) {
        const job = queueService.enqueueJob('slow-source');
        await queueService.executeJobWithRecovery(
          job.id,
          operation,
          slowConfig
        );
      }

      // Slow source: 3rd request should fail
      const job = queueService.enqueueJob('slow-source');
      await expect(
        queueService.executeJobWithRecovery(
          job.id,
          operation,
          slowConfig
        )
      ).rejects.toThrow();
    });
  });

  describe('Rate Limiting with Circuit Breaker', () => {
    it('should work with circuit breaker', async () => {
      const rateLimitConfig: ScraperRateLimitConfig = {
        requestsPerMinute: 10,
      };

      const operation = vi.fn().mockResolvedValue({ success: true });

      const job = queueService.enqueueJob('source-1');
      const result = await queueService.executeJobWithRecovery(
        job.id,
        operation,
        rateLimitConfig
      );

      expect(result).toEqual({ success: true });

      // Check circuit breaker stats
      const cbStats = queueService.getCircuitBreakerStats('source-1');
      expect(cbStats).toBeDefined();
    });

    it('should handle circuit breaker open state', async () => {
      const rateLimitConfig: ScraperRateLimitConfig = {
        requestsPerMinute: 10,
      };

      // Create multiple failing jobs to open circuit breaker
      const failingOperation = vi.fn().mockRejectedValue(new Error('Network error'));

      for (let i = 0; i < 5; i++) {
        const job = queueService.enqueueJob('source-1');
        try {
          await queueService.executeJobWithRecovery(
            job.id,
            failingOperation,
            rateLimitConfig
          );
        } catch (error) {
          // Expected to fail
        }
      }

      // Circuit breaker should be open
      const cbStats = queueService.getCircuitBreakerStats('source-1');
      expect(cbStats?.state).toBe('OPEN');
    });
  });

  describe('Queue Statistics with Rate Limiting', () => {
    it('should include rate limit info in queue stats', async () => {
      const rateLimitConfig: ScraperRateLimitConfig = {
        requestsPerMinute: 10,
      };

      // Enqueue some jobs
      queueService.enqueueJob('source-1');
      queueService.enqueueJob('source-2');

      const stats = queueService.getQueueStats();

      expect(stats.total).toBe(2);
      expect(stats.pending).toBe(2);
    });

    it('should track rate limit statuses across multiple sources', async () => {
      const rateLimitConfig: ScraperRateLimitConfig = {
        requestsPerMinute: 5,
      };

      // Make requests for different sources
      await scraperRateLimiter.checkRateLimit('source-1', rateLimitConfig);
      await scraperRateLimiter.checkRateLimit('source-2', rateLimitConfig);
      await scraperRateLimiter.checkRateLimit('source-1', rateLimitConfig);

      const statuses = queueService.getAllRateLimitStatuses();

      expect(statuses['source-1'].requestsInLastMinute).toBe(2);
      expect(statuses['source-2'].requestsInLastMinute).toBe(1);
    });
  });

  describe('Error Recovery with Rate Limiting', () => {
    it('should retry with exponential backoff on rate limit errors', async () => {
      const rateLimitConfig: ScraperRateLimitConfig = {
        requestsPerMinute: 1,
      };

      let attemptCount = 0;
      const operation = vi.fn(async () => {
        attemptCount++;
        if (attemptCount === 1) {
          // First attempt succeeds
          return { success: true };
        }
        throw new Error('Should not reach here');
      });

      const job = queueService.enqueueJob('source-1');
      await queueService.executeJobWithRecovery(
        job.id,
        operation,
        rateLimitConfig
      );

      expect(attemptCount).toBe(1);
    });

    it('should handle permanent failures correctly', async () => {
      const rateLimitConfig: ScraperRateLimitConfig = {
        requestsPerMinute: 10,
      };

      const operation = vi.fn().mockRejectedValue(new Error('Permanent error'));

      const job = queueService.enqueueJob('source-1', { maxRetries: 2 });

      await expect(
        queueService.executeJobWithRecovery(
          job.id,
          operation,
          rateLimitConfig
        )
      ).rejects.toThrow('Permanent error');

      const failedJob = queueService.getJobStatus(job.id);
      expect(failedJob?.status).toBe('FAILED');
      expect(failedJob?.retryCount).toBeGreaterThan(0);
    });
  });

  describe('Concurrent Job Execution with Rate Limiting', () => {
    it('should handle concurrent jobs with rate limiting', async () => {
      const rateLimitConfig: ScraperRateLimitConfig = {
        requestsPerMinute: 5,
        minDelay: 50,
      };

      const operation = vi.fn().mockResolvedValue({ success: true });

      // Create 3 jobs
      const jobs = [
        queueService.enqueueJob('source-1'),
        queueService.enqueueJob('source-1'),
        queueService.enqueueJob('source-1'),
      ];

      // Execute them concurrently
      const start = Date.now();
      const results = await Promise.all(
        jobs.map(job =>
          queueService.executeJobWithRecovery(
            job.id,
            operation,
            rateLimitConfig
          )
        )
      );
      const elapsed = Date.now() - start;

      // All should succeed
      expect(results).toHaveLength(3);
      results.forEach(result => {
        expect(result).toEqual({ success: true });
      });

      // Should have taken at least 100ms (2 * minDelay) due to rate limiting
      expect(elapsed).toBeGreaterThanOrEqual(100);
    });

    it('should respect max concurrent jobs', async () => {
      const queueService2 = new ScraperQueueService(2); // Max 2 concurrent

      const rateLimitConfig: ScraperRateLimitConfig = {
        requestsPerMinute: 10,
      };

      let concurrentCount = 0;
      let maxConcurrent = 0;

      const operation = vi.fn(async () => {
        concurrentCount++;
        maxConcurrent = Math.max(maxConcurrent, concurrentCount);
        await new Promise(resolve => setTimeout(resolve, 50));
        concurrentCount--;
        return { success: true };
      });

      // Create 5 jobs
      const jobs = Array.from({ length: 5 }, () =>
        queueService2.enqueueJob('source-1')
      );

      // Execute them
      await Promise.all(
        jobs.map(job =>
          queueService2.executeJobWithRecovery(
            job.id,
            operation,
            rateLimitConfig
          )
        )
      );

      // Max concurrent should not exceed 2
      expect(maxConcurrent).toBeLessThanOrEqual(2);

      queueService2.clearAll();
    });
  });

  describe('Rate Limit Reset and Management', () => {
    it('should reset rate limit and allow new requests', async () => {
      const rateLimitConfig: ScraperRateLimitConfig = {
        requestsPerMinute: 1,
      };

      // Make a request
      await scraperRateLimiter.checkRateLimit('source-1', rateLimitConfig);

      // Should be at limit
      await expect(
        scraperRateLimiter.checkRateLimit('source-1', rateLimitConfig)
      ).rejects.toThrow();

      // Reset via queue service
      queueService.resetRateLimit('source-1');

      // Should work now
      await expect(
        scraperRateLimiter.checkRateLimit('source-1', rateLimitConfig)
      ).resolves.not.toThrow();
    });

    it('should reset circuit breaker independently of rate limit', async () => {
      const rateLimitConfig: ScraperRateLimitConfig = {
        requestsPerMinute: 10,
      };

      // Make failing requests to open circuit breaker
      const failingOp = vi.fn().mockRejectedValue(new Error('Fail'));

      for (let i = 0; i < 5; i++) {
        const job = queueService.enqueueJob('source-1');
        try {
          await queueService.executeJobWithRecovery(
            job.id,
            failingOp,
            rateLimitConfig
          );
        } catch (error) {
          // Expected
        }
      }

      // Reset circuit breaker
      queueService.resetCircuitBreaker('source-1');

      // Circuit breaker should be closed
      const cbStats = queueService.getCircuitBreakerStats('source-1');
      expect(cbStats?.state).toBe('CLOSED');
    });
  });
